values
('additional-maths:6-2-the-binomial-expansion:mcq:80da08b9', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'mcq', 'mcq', 1, '{"question": "A student writes the \\( x^2 \\) term of \\( (2+3x)^5 \\) as \\( 90x^2 \\). What did they do wrong?", "options": ["They forgot to raise the \\( 2 \\): it is \\( 10\\times 2^3\\times 3^2 = 720x^2 \\)", "Nothing — it is correct", "They should have used \\( {}^5C_3 \\)", "They forgot the \\( x^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 90 = 10\\times 9 \\) misses \\( 2^3 = 8 \\); the correct coefficient is \\( 10\\times 8\\times 9 = 720 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:mcq:b0f0aaa6', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'mcq', 'mcq', 1, '{"question": "What is the coefficient of \\( x^3 \\) in \\( (1-2x)^4 \\)?", "options": ["\\( -32 \\)", "\\( 32 \\)", "\\( -8 \\)", "\\( -24 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( r=3 \\): \\( {}^4C_3\\,(-2)^3 = 4\\times(-8) = -32 \\). The odd power of \\( -2 \\) makes it negative."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:bcdd1250', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "The expansion of \\( (a+b)^n \\) has \\( n \\) terms."}'::jsonb, '{"answer": false, "explain": "It has \\( n+1 \\) terms — one more than the power."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:47066623', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "In \\( (a+b)^n \\) the powers of \\( a \\) decrease while the powers of \\( b \\) increase, and each term''s powers add to \\( n \\)."}'::jsonb, '{"answer": true, "explain": "The powers of \\( a \\) run \\( n, n-1, \\dots, 0 \\) and of \\( b \\) run \\( 0, 1, \\dots, n \\); they always sum to \\( n \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:233fb96a', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "The row of Pascal''s triangle for \\( (a+b)^3 \\) is \\( 1,\\ 3,\\ 3,\\ 1 \\)."}'::jsonb, '{"answer": true, "explain": "Row 3 is \\( 1,\\ 3,\\ 3,\\ 1 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:cfd1d842', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "\\( {}^nC_r \\) is printed on the 6993 formula sheet, so you do not have to memorise it."}'::jsonb, '{"answer": true, "explain": "The binomial series and \\( {}^nC_r \\) are provided; only formulae like the quadratic formula and log laws must be memorised."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:a0f74cee', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "The general term of \\( (a+b)^n \\) is \\( {}^nC_r\\, a^r b^{n-r} \\)."}'::jsonb, '{"answer": false, "explain": "The powers are the other way round: \\( {}^nC_r\\, a^{n-r} b^r \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:2954dd4e', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "To expand \\( (2+3x)^4 \\), the coefficient of the \\( x^2 \\) term must include \\( 3^2 \\)."}'::jsonb, '{"answer": true, "explain": "The whole \\( 3x \\) is raised to the power, so \\( (3x)^2 = 9x^2 \\) — the 3 is squared."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:0fc348ed', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "\"The term independent of \\( x \\)\" is always the first term of the expansion."}'::jsonb, '{"answer": false, "explain": "It is the constant term — the one where the power of \\( x \\) is \\( 0 \\), which need not be first."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tf:f3885c13', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tf', 'tf', 1, '{"question": "In \\( (1-2x)^5 \\) the terms alternate in sign."}'::jsonb, '{"answer": true, "explain": "Each term has \\( (-2x)^r \\), and \\( (-1)^r \\) alternates \\( +,-,+,-,\\dots \\)"}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:learn:ff3e3d89', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'learn', 'mcq', 1, '{"readingTitle": "What is the binomial expansion?", "reading": "<p>A <strong>binomial</strong> is an expression with two terms, such as \\( a + b \\). The <strong>binomial expansion</strong> multiplies out \\( (a+b)^n \\) for a positive integer \\( n \\) without doing all the bracket multiplication by hand.</p>\n            <ul>\n              <li>\\( (a+b)^n \\) expands into \\( n+1 \\) terms.</li>\n              <li>The <strong>powers of \\( a \\) go down</strong> from \\( n \\) to \\( 0 \\); the <strong>powers of \\( b \\) go up</strong> from \\( 0 \\) to \\( n \\). In <em>every</em> term the two powers add up to \\( n \\).</li>\n              <li>Each term carries a <strong>binomial coefficient</strong>. For example \\[ (a+b)^4 = a^4 + 4a^3 b + 6a^2 b^2 + 4a b^3 + b^4. \\]</li>\n            </ul>\n            <p>Notice the coefficients \\( 1,\\ 4,\\ 6,\\ 4,\\ 1 \\) read the same forwards and backwards — they are symmetric.</p>", "question": "How many terms are in the expansion of \\( (a+b)^7 \\)?", "options": ["\\( 8 \\)", "\\( 7 \\)", "\\( 6 \\)", "\\( 14 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (a+b)^n \\) has \\( n+1 \\) terms, so \\( (a+b)^7 \\) has \\( 8 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:learn:4c9570c9', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'learn', 'mcq', 1, '{"readingTitle": "Where do the coefficients come from — Pascal''s triangle?", "reading": "<p><strong>Pascal''s triangle</strong> is a quick way to write down the coefficients. Each number is the sum of the two numbers above it; row \\( n \\) gives the coefficients of \\( (a+b)^n \\).</p>\n            <table class=\"worked\">\n              <tr><td>\\( n=0 \\)</td><td>1</td></tr>\n              <tr><td>\\( n=1 \\)</td><td>1&nbsp;&nbsp;1</td></tr>\n              <tr><td>\\( n=2 \\)</td><td>1&nbsp;&nbsp;2&nbsp;&nbsp;1</td></tr>\n              <tr><td>\\( n=3 \\)</td><td>1&nbsp;&nbsp;3&nbsp;&nbsp;3&nbsp;&nbsp;1</td></tr>\n              <tr><td>\\( n=4 \\)</td><td>1&nbsp;&nbsp;4&nbsp;&nbsp;6&nbsp;&nbsp;4&nbsp;&nbsp;1</td></tr>\n              <tr><td>\\( n=5 \\)</td><td>1&nbsp;&nbsp;5&nbsp;&nbsp;10&nbsp;&nbsp;10&nbsp;&nbsp;5&nbsp;&nbsp;1</td></tr>\n            </table>\n            <p>The triangle is fine for small \\( n \\), but drawing it out to (say) row 12 is slow and error-prone — that is where \\( {}^nC_r \\) is faster.</p>", "question": "Which row of Pascal''s triangle gives the coefficients of \\( (a+b)^5 \\)?", "options": ["\\( 1,\\ 5,\\ 10,\\ 10,\\ 5,\\ 1 \\)", "\\( 1,\\ 4,\\ 6,\\ 4,\\ 1 \\)", "\\( 1,\\ 5,\\ 5,\\ 1 \\)", "\\( 1,\\ 6,\\ 15,\\ 20,\\ 15,\\ 6,\\ 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "Row \\( n=5 \\) is \\( 1,\\ 5,\\ 10,\\ 10,\\ 5,\\ 1 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:learn:edcecccf', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'learn', 'mcq', 1, '{"readingTitle": "How do you use \\( {}^nC_r \\) for the coefficients?", "reading": "<p>The binomial coefficients are the numbers \\( {}^nC_r \\) (say \"n choose r\"), given by \\[ {}^nC_r = \\frac{n!}{r!\\,(n-r)!}. \\] Your calculator has an \\( {}^nC_r \\) button, so you never need to expand the factorials by hand.</p>\n            <ul>\n              <li>Both the <strong>binomial series</strong> and \\( {}^nC_r \\) are <strong>PROVIDED on the exam formula sheet</strong> — you do not have to memorise them, but you <em>must</em> apply them correctly.</li>\n              <li>\\( {}^nC_0 = 1 \\) and \\( {}^nC_n = 1 \\) always (the first and last coefficients).</li>\n              <li>Example: \\( {}^6C_2 = \\dfrac{6!}{2!\\,4!} = 15 \\), which matches row 6 of Pascal''s triangle.</li>\n            </ul>\n            <p>For contrast, the quadratic formula, the log laws and the sine/cosine rules are <strong>NOT</strong> on the sheet — those you must memorise.</p>", "question": "Which formulae are PROVIDED on the 6993 formula sheet?", "options": ["The binomial series and \\( {}^nC_r \\)", "The quadratic formula", "The log laws", "The sine and cosine rules"]}'::jsonb, '{"answer": 0, "explain": "The binomial series and \\( {}^nC_r \\) are printed on the sheet; the others must be memorised."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:learn:9b5b73bb', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'learn', 'mcq', 1, '{"readingTitle": "What is the general term of \\( (a+b)^n \\)?", "reading": "<p>Rather than write out the whole expansion, you can jump straight to any term using the <strong>general term</strong>: \\[ {}^nC_r\\, a^{\\,n-r}\\, b^{\\,r}, \\qquad r = 0,\\ 1,\\ 2,\\ \\dots,\\ n. \\]</p>\n            <ul>\n              <li>The power of \\( a \\) is \\( n-r \\); the power of \\( b \\) is \\( r \\); together they add to \\( n \\).</li>\n              <li>\\( r = 0 \\) gives the first term, \\( r = 1 \\) the second, and so on — so the term with \\( b^r \\) is the \\( (r+1)\\text{th} \\) term. Mind that off-by-one.</li>\n            </ul>\n            <p><strong>Worked example — the term in \\( a^4 b^2 \\) of \\( (a+b)^6 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. The power of \\( b \\) is \\( 2 \\), so \\( r = 2 \\).</td></tr>\n              <tr><td>2. Coefficient: \\( {}^6C_2 = 15 \\).</td></tr>\n              <tr><td>3. Term: \\( {}^6C_2\\, a^{6-2} b^2 = 15\\,a^4 b^2 \\).</td></tr>\n            </table>", "question": "In the general term \\( {}^nC_r\\, a^{n-r} b^r \\), what is the power of \\( b \\)?", "options": ["\\( r \\)", "\\( n-r \\)", "\\( n \\)", "\\( r-1 \\)"]}'::jsonb, '{"answer": 0, "explain": "The power of \\( b \\) is \\( r \\); the power of \\( a \\) is \\( n-r \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:learn:65285105', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'learn', 'mcq', 1, '{"readingTitle": "How do you expand something like \\( (2+3x)^5 \\)?", "reading": "<p>When a term is a number times a variable, such as \\( 3x \\), the power applies to the <strong>whole</strong> part — you must raise the number too, e.g. \\( (3x)^2 = 9x^2 \\), not \\( 3x^2 \\).</p>\n            <p><strong>Worked example — expand \\( (2+3x)^5 \\):</strong> here \\( a = 2 \\), \\( b = 3x \\), \\( n = 5 \\), so the general term is \\( {}^5C_r\\, 2^{\\,5-r}(3x)^r \\).</p>\n            <table class=\"worked\">\n              <tr><td>\\( r=0 \\): \\( {}^5C_0\\, 2^5 = 32 \\)</td></tr>\n              <tr><td>\\( r=1 \\): \\( {}^5C_1\\, 2^4 (3x) = 5\\times 16\\times 3\\,x = 240x \\)</td></tr>\n              <tr><td>\\( r=2 \\): \\( {}^5C_2\\, 2^3 (3x)^2 = 10\\times 8\\times 9\\,x^2 = 720x^2 \\)</td></tr>\n              <tr><td>\\( r=3 \\): \\( {}^5C_3\\, 2^2 (3x)^3 = 10\\times 4\\times 27\\,x^3 = 1080x^3 \\)</td></tr>\n              <tr><td>\\( r=4 \\): \\( {}^5C_4\\, 2^1 (3x)^4 = 5\\times 2\\times 81\\,x^4 = 810x^4 \\)</td></tr>\n              <tr><td>\\( r=5 \\): \\( {}^5C_5\\, (3x)^5 = 243x^5 \\)</td></tr>\n            </table>\n            <p>So \\[ (2+3x)^5 = 32 + 240x + 720x^2 + 1080x^3 + 810x^4 + 243x^5. \\]</p>", "question": "In the \\( x^2 \\) term of \\( (2+3x)^5 \\), which factor is easy to forget?", "options": ["\\( 3^2 = 9 \\) (raising the 3 to the power)", "The \\( {}^5C_2 \\) coefficient only", "The \\( x^2 \\)", "Nothing — you just add the terms"]}'::jsonb, '{"answer": 0, "explain": "The \\( 3 \\) must be squared: \\( 10\\times 2^3\\times 3^2 = 720 \\), not \\( 10\\times 2^3 = 80 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:learn:27b793b7', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'learn', 'mcq', 1, '{"readingTitle": "How do you find a specific term, coefficient, or the term independent of \\( x \\)?", "reading": "<p>You rarely need the whole expansion — pick out the one term you want with the general term.</p>\n            <p><strong>To find the coefficient of a power of \\( x \\):</strong> write the general term, collect the power of \\( x \\), set it equal to the power you want, solve for \\( r \\), then evaluate.</p>\n            <table class=\"worked\">\n              <tr><td>Coefficient of \\( x^3 \\) in \\( (2+3x)^5 \\): general term \\( {}^5C_r\\, 2^{5-r}(3x)^r \\) has \\( x^r \\), so \\( r=3 \\).</td></tr>\n              <tr><td>Value: \\( {}^5C_3\\, 2^2\\, 3^3 = 10\\times 4\\times 27 = 1080 \\).</td></tr>\n            </table>\n            <p><strong>The term \"independent of \\( x \\)\"</strong> is the <strong>constant term</strong> — the one where the power of \\( x \\) is \\( 0 \\). This appears when the bracket has both a positive and a negative power of \\( x \\).</p>\n            <table class=\"worked\">\n              <tr><td>Term independent of \\( x \\) in \\( \\left(x - \\dfrac{3}{x^2}\\right)^6 \\): general term \\( {}^6C_r\\, x^{6-r}\\left(-\\dfrac{3}{x^2}\\right)^r = {}^6C_r\\,(-3)^r\\, x^{\\,6-3r} \\).</td></tr>\n              <tr><td>Independent of \\( x \\) when \\( 6-3r = 0 \\), i.e. \\( r=2 \\).</td></tr>\n              <tr><td>Value: \\( {}^6C_2\\,(-3)^2 = 15\\times 9 = 135 \\).</td></tr>\n            </table>\n            <p><strong>Always state the term clearly at the end</strong> — an answer left buried inside a long expansion loses the final mark.</p>", "question": "\"The term independent of \\( x \\)\" means the term in which the power of \\( x \\) is:", "options": ["\\( 0 \\) (the constant term)", "\\( 1 \\)", "the highest power", "the lowest positive power"]}'::jsonb, '{"answer": 0, "explain": "Independent of \\( x \\) means \\( x^0 \\) — a constant with no \\( x \\) in it."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:misc:89fdadd5', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Coefficient of \\( x^2 \\) in \\( (2+3x)^5 \\) is \\( {}^5C_2\\times 2^3 = 80 \\)</p><p><strong>✅ The correct idea:</strong> The \\( 3 \\) must also be raised to the power: \\( (3x)^2 = 9x^2 \\). A weak answer uses only \\( 2^3 \\); a strong answer writes \\( {}^5C_2\\times 2^3\\times 3^2 = 10\\times 8\\times 9 = 720 \\).</p>", "question": "Coefficient of \\( x^2 \\) in \\( (2+3x)^5 \\)?", "options": ["\\( 720 \\)", "\\( 80 \\)", "\\( 90 \\)", "\\( 10 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( {}^5C_2\\times 2^3\\times 3^2 = 720 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:misc:15a8f100', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The third term of \\( (a+b)^6 \\) is \\( a^4 b^2 \\)</p><p><strong>✅ The correct idea:</strong> You must include the binomial coefficient. A weak answer drops the \\( {}^nC_r \\); a strong answer writes \\( {}^6C_2\\, a^4 b^2 = 15\\,a^4 b^2 \\).</p>", "question": "The third term of \\( (a+b)^6 \\) is:", "options": ["\\( 15\\,a^4 b^2 \\)", "\\( a^4 b^2 \\)", "\\( 6\\,a^4 b^2 \\)", "\\( 20\\,a^4 b^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( r=2 \\): \\( {}^6C_2 = 15 \\), so \\( 15\\,a^4 b^2 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:misc:704728aa', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The 4th term of \\( (a+b)^6 \\) uses \\( r = 4 \\), giving \\( 15\\,a^2 b^4 \\)</p><p><strong>✅ The correct idea:</strong> The term with \\( b^r \\) is the \\( (r+1)\\text{th} \\) term, so the 4th term has \\( r=3 \\). A strong answer gives \\( {}^6C_3\\, a^3 b^3 = 20\\,a^3 b^3 \\).</p>", "question": "Which \\( r \\) gives the 4th term of \\( (a+b)^6 \\)?", "options": ["\\( r = 3 \\)", "\\( r = 4 \\)", "\\( r = 5 \\)", "\\( r = 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "The \\( (r+1)\\text{th} \\) term uses \\( r \\), so the 4th term is \\( r=3 \\)."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:misc:bf5e5e40', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For \\( \\left(x+\\frac{2}{x}\\right)^6 \\), the term independent of \\( x \\) is the first term</p><p><strong>✅ The correct idea:</strong> Independent of \\( x \\) means the power of \\( x \\) is \\( 0 \\). A weak answer guesses a position; a strong answer sets the power to \\( 0 \\), solves for \\( r \\), and evaluates that one term.</p>", "question": "How do you find the term independent of \\( x \\)?", "options": ["Set the power of \\( x \\) to \\( 0 \\) and solve for \\( r \\)", "Take the first term", "Take the middle term always", "Take the last term"]}'::jsonb, '{"answer": 0, "explain": "Set the collected power of \\( x \\) equal to \\( 0 \\), find \\( r \\), then evaluate."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:misc:605d3015', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Coefficient of \\( x^3 \\) in \\( (1-2x)^4 \\) is \\( +32 \\)</p><p><strong>✅ The correct idea:</strong> The sign matters: \\( (-2)^3 = -8 \\). A weak answer ignores the minus; a strong answer writes \\( {}^4C_3(-2)^3 = 4\\times(-8) = -32 \\).</p>", "question": "Coefficient of \\( x^3 \\) in \\( (1-2x)^4 \\)?", "options": ["\\( -32 \\)", "\\( 32 \\)", "\\( -8 \\)", "\\( 8 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( {}^4C_3(-2)^3 = -32 \\); an odd power of a negative is negative."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tips:c56ab465', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tips', 'mcq', 1, '{"readingTitle": "tip — Use the formula you are given", "reading": "<p>The binomial series and \\( {}^nC_r \\) are printed on the formula sheet, yet the 2023 examiners noted that weaker candidates did not use them — some drew Pascal''s triangle but got stuck, and others tried to multiply out six brackets.</p><p><strong>Full marks path for a \"term\" question:</strong> write the general term \\( {}^nC_r\\, a^{n-r} b^r \\) (M1), get the correct powers/numbers for the term asked for (DM1), then state the single value clearly (A1).</p>", "question": "Why quote the general term from the formula sheet?", "options": ["It gives a reliable method that earns the method marks", "It is banned in the exam", "It only works for \\( n<4 \\)", "It avoids using a calculator"]}'::jsonb, '{"answer": 0, "explain": "Applying the provided formula is the method the mark scheme rewards."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tips:7ceb58f0', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tips', 'mcq', 1, '{"readingTitle": "explain — State the term clearly — do not bury it", "reading": "<p>The 2023 mark scheme awarded the final A1 only if the requested term was <strong>clearly identified and not just embedded in the expansion</strong>. A candidate who correctly wrote out every term but never picked out the \\( 160 \\) could not score full marks.</p><p><strong>Habit:</strong> finish with a sentence like \"The term independent of \\( x \\) is \\( 160 \\).\"</p>", "question": "You have written the full correct expansion. What must you still do?", "options": ["Clearly state the specific term the question asked for", "Nothing — it is automatic", "Round to 3 s.f.", "Draw Pascal''s triangle"]}'::jsonb, '{"answer": 0, "explain": "The A1 needs the requested term identified explicitly."}'::jsonb),
('additional-maths:6-2-the-binomial-expansion:tips:6eb4ed61', 'additional-maths', 'additional-maths:6-2-the-binomial-expansion', '6.2 The Binomial Expansion', 'tips', 'mcq', 1, '{"readingTitle": "tip — Raise the WHOLE bracket part to the power", "reading": "<p>In \\( (2+3x)^5 \\) the term is \\( {}^5C_r\\, 2^{5-r}(3x)^r \\) — the \\( (3x)^r \\) means \\( 3^r x^r \\), so the number is raised too. Forgetting \\( 3^r \\) (or the sign of a negative term) is the single most common slip on these questions.</p>", "question": "In \\( (2+3x)^5 \\), what is \\( (3x)^2 \\)?", "options": ["\\( 9x^2 \\)", "\\( 3x^2 \\)", "\\( 6x^2 \\)", "\\( 9x \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (3x)^2 = 3^2 x^2 = 9x^2 \\); the coefficient is squared as well."}'::jsonb),
